// HMAC-SHA256 verification of the db-write-pipeline proposal.
// Webhook options.rawBody=true → raw bytes at item.binary.data (base64).
const crypto = require("crypto");
const secret = $env.N8N_DB_PIPELINE_WEBHOOK_SECRET;
if (!secret) throw new Error("N8N_DB_PIPELINE_WEBHOOK_SECRET env not set");

const item = $input.first();
const headers = (item.json || {}).headers || {};
const presented = headers["x-ratis-signature"] || headers["X-Ratis-Signature"];
if (!presented) return { json: { _hmac_status: "missing_signature" } };

const bin = item.binary && item.binary.data;
if (!bin || !bin.data) return { json: { _hmac_status: "raw_body_unavailable" } };

const rawBuf = Buffer.from(bin.data, "base64");
const expected = crypto.createHmac("sha256", secret).update(rawBuf).digest("hex");
const a = Buffer.from(presented, "hex");
const b = Buffer.from(expected, "hex");
if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) {
  return { json: { _hmac_status: "invalid_signature" } };
}
// Valid — pass the parsed proposal through.
const proposal = (item.json || {}).body || {};
return { json: { ...proposal, _hmac_status: "ok" } };

// L2 — rate-limit webhook avant les appels LLM coûteux côté Anthropic.
// Sliding window 20 propositions / 60s, mémoire workflow ($workflow.staticData).
// Au-delà : on coupe avant Validate identity / args / LLM. Defense in depth
// avec le throttle 10/min côté agent-mcp et le budget cap Anthropic (PROD_CHECKLIST).
const j = $input.first().json;
const now = Date.now();
const WINDOW_MS = 60 * 1000;
const MAX_PER_MINUTE = 20;
const data = $workflow.staticData || {};
const recent = (data.recentPropositionMs || []).filter(t => now - t < WINDOW_MS);
if (recent.length >= MAX_PER_MINUTE) {
  return { json: { ...j, _rate_limit_status: 'rejected', _rate_limit_recent_count: recent.length } };
}
recent.push(now);
data.recentPropositionMs = recent;
$workflow.staticData = data;
return { json: { ...j, _rate_limit_status: 'ok', _rate_limit_recent_count: recent.length } };

// Runs the proposal in the sandbox and evaluates the structured `checks`.
// The sandbox container name comes from the Sandbox Up node output.
// docker exec into the sandbox to apply CALL + evaluate checks.
const { execSync } = require("child_process");
const p = $('IF HMAC OK').first().json;
const up = $('Sandbox Up').first().json;
// Sandbox Up prints JSON {sandbox_id, container} on stdout.
const upOut = JSON.parse((up.stdout || "{}").trim().split("\n").pop());
const container = upOut.container;
const sandboxId = upOut.sandbox_id;

// M7 — defense in depth : validate sandbox identifier shape before any
// interpolation into a shell command. `sandbox-up.sh` generates the id via
// `date +%s-$RANDOM` (digits-dash-digits) — anything else is suspicious and
// short-circuits the proposal. Same check on container (ratis-sandbox-<id>).
if (!/^[0-9]+-[0-9]+$/.test(String(sandboxId || ""))) {
  return { json: { ...p, _outcome: "rejected_sandbox_id_invalid", _sandbox_id: null, _invariants_ok: false, _report: `[db-write-pipeline] proposal ${p.submission_id} REJECTED — invalid sandbox_id shape from sandbox-up.sh` } };
}
if (!/^ratis-sandbox-[0-9]+-[0-9]+$/.test(String(container || ""))) {
  return { json: { ...p, _outcome: "rejected_sandbox_id_invalid", _sandbox_id: sandboxId, _invariants_ok: false, _report: `[db-write-pipeline] proposal ${p.submission_id} REJECTED — invalid sandbox container shape from sandbox-up.sh` } };
}

function sql(q) {
  const cmd = `ssh mac-mini-host "docker exec -i ${container} psql -U ratis -d ratis_prod -tA -v ON_ERROR_STOP=1"`;
  return execSync(cmd, { input: q, encoding: "utf-8" }).trim();
}

let invariantsOk = true;
const results = [];
try {
  // HSP4 M4 — mode=new supprimé : la procédure existe déjà dans le catalogue
  // (déployée hors-pipeline). On ne fait plus que CALL + checks.
  // Snapshot the `delta` check queries BEFORE.
  const before = {};
  for (const c of p.checks) if (c.type === "delta") before[c.query] = sql(c.query);
  // M5 fix — argOrder from manifest.args (not insertion order of p.args).
  // The manifest is populated upstream by `Validate args` and lives on the
  // proposal as `_manifest_snapshot`. Same sqlQuote logic as `Execute`.
  const manifest = $('Validate args').first().json._manifest_snapshot || {};
  const argOrder = (manifest.args || []).map(a => a.name);
  function sqlQuote(v) {
    if (typeof v === "number") return String(v);
    if (typeof v === "boolean") return v ? "true" : "false";
    if (v === null || v === undefined) return "NULL";
    return "'" + String(v).replace(/'/g, "''") + "'";
  }
  const callArgs = argOrder.map(name => sqlQuote(p.args[name])).join(", ");
  sql(`CALL ${p.procedure}(${callArgs})`);
  for (const c of p.checks) {
    if (c.type === "delta") {
      const after = sql(c.query);
      const got = Number(after) - Number(before[c.query]);
      const ok = got === Number(c.expect);
      results.push({ check: "delta", query: c.query, expect: c.expect, got, ok });
      if (!ok) invariantsOk = false;
    }
    // `rowcount` checks are validated at execution time (procedure OUT param) —
    // the stub records them as informational here.
    if (c.type === "rowcount") results.push({ check: "rowcount", expect: c.expect, ok: true });
  }
} catch (e) {
  invariantsOk = false;
  results.push({ error: String(e).slice(0, 300) });
}
return { json: { ...p, _sandbox_id: sandboxId, _invariants_ok: invariantsOk, _check_results: results } };

// HSP4 M5 — exécution prod avec checksum per-call.
// 1. BEGIN ; SET LOCAL app.submission_id = '<uuid>' ; SET LOCAL app.caps_enforced = 'true' ;
// 2. CALL support_<name>(<args>) ;
// 3. POST PA /check-rowcount → compare db_change_log au manifeste.
// 4. mismatch → ROLLBACK + freeze procedure via apply-graduation + alerte Discord.
// 5. ok → COMMIT.
//
// Le binaire psql est invoqué via docker exec sur le container prod ratis-postgres-1.
// Le rôle utilisé reste `ratis` admin en HSP4 — le swap à `agent_read` est HSP5.
const { execSync } = require('child_process');
const https = require('https');
const http = require('http');
const j = $input.first().json;
const submissionId = j.submission_id;
const procedure = j.procedure;
const args = j.args || {};
const manifest = j._manifest_snapshot || {};

// L1 fix — flag lu via env n8n DB_PIPELINE_EXECUTE_ENABLED. Fail-safe :
// absent OU !== 'true' (string match strict) → execute DISABLED.
const EXECUTE_ENABLED = $env.DB_PIPELINE_EXECUTE_ENABLED === 'true';
if (!EXECUTE_ENABLED) {
  return { json: { ...j, _report: `[db-write-pipeline] proposal ${submissionId} execute DISABLED (flag off)` } };
}

// Helper : run SQL dans une session psql (NULL = run-and-discard ; les CALL doivent
// rester dans une SEULE transaction donc on passe tout le script en input stdin).
function runScript(script) {
  const cmd = `ssh mac-mini-host "docker exec -i ratis-postgres-1 psql -U ratis -d ratis_prod -tA -v ON_ERROR_STOP=1"`;
  return execSync(cmd, { input: script, encoding: 'utf-8' });
}

// Build le CALL avec args ordered selon manifest.args (l'ordre des positions est
// stable par construction TOML — args list est ordonnée). Les args sont *bind* via
// psql `\set` côté driver natif idéalement ; en l'absence, on quote prudemment.
const argOrder = (manifest.args || []).map(a => a.name);
function sqlQuote(v) {
  if (typeof v === 'number') return String(v);
  if (typeof v === 'boolean') return v ? 'true' : 'false';
  if (v === null || v === undefined) return 'NULL';
  // String : escape simple quote.
  return "'" + String(v).replace(/'/g, "''") + "'";
}
const callArgs = argOrder.map(name => sqlQuote(args[name])).join(', ');
// Ajout de NULL pour le OUT param rows_affected (convention HSP1).
const script = `BEGIN;
SET LOCAL app.submission_id = '${submissionId}';
SET LOCAL app.caps_enforced = 'true';
CALL ${procedure}(${callArgs}${callArgs ? ', ' : ''}NULL);
-- Pas de COMMIT/ROLLBACK ici — on rend la transaction OUVERTE pour qu'on puisse
-- inspecter db_change_log dans une 2ᵉ commande après. Sauf que psql en mode -1
-- (single transaction) ferme à la fin... donc on inline le SELECT du checksum
-- dans le même script et on commit/rollback selon le résultat retourné en stdout.
SELECT table_name || ':' || COUNT(*) FROM db_change_log
WHERE submission_id = '${submissionId}'::uuid GROUP BY table_name;
COMMIT;`;

let stdout;
try {
  stdout = runScript(script);
} catch (e) {
  // Le CALL ou le checksum a raised → la transaction est rolled-back côté PG.
  // ON_ERROR_STOP=1 + erreur côté psql + transaction abort = pas de commit.
  return { json: { ...j, _execute_outcome: 'rollback_call_error', _execute_detail: String(e.stderr || e).slice(0, 500), _report: `[db-write-pipeline] proposal ${submissionId} ROLLBACK (CALL error)` } };
}

// Parse stdout : lignes `table:count`.
const observed = {};
for (const line of stdout.split('\n')) {
  const m = line.trim().match(/^([a-z_]+):([0-9]+)$/);
  if (m) observed[m[1]] = Number(m[2]);
}

// Compare au manifeste via PA /check-rowcount (single source = Python).
// Note : la transaction est déjà COMMIT à ce stade (psql -1 ne marche pas avec
// notre script multi-statement). HSP4 V1.1 documente ce trade-off : on COMMIT
// puis on check, et en cas de mismatch on émet un INCIDENT au lieu d'un
// ROLLBACK (qui ne serait plus possible). Pour V1.2, refactorer en JS direct
// avec une connexion node-postgres persistante pour bénéficier du ROLLBACK
// vraiment atomique. Cf docs/superpowers/specs/...-v1.2-checksum-rollback.md.
const paUrl = $env.PA_INTERNAL_BASE_URL + '/api/v1/admin/db-pipeline/check-rowcount';
const internalKey = $env.INTERNAL_API_KEY;
const body = JSON.stringify({ submission_id: submissionId, manifest });
const checkRes = await new Promise((resolve, reject) => {
  const u = new URL(paUrl);
  const lib = u.protocol === 'https:' ? https : http;
  const req = lib.request({
    method: 'POST', hostname: u.hostname, port: u.port || (u.protocol === 'https:' ? 443 : 80),
    path: u.pathname,
    headers: { 'Content-Type': 'application/json', 'X-Internal-API-Key': internalKey, 'Content-Length': Buffer.byteLength(body) },
  }, (res) => { let buf = ''; res.on('data', (c) => { buf += c; }); res.on('end', () => resolve({ status: res.statusCode, body: buf })); });
  req.on('error', reject);
  req.write(body); req.end();
});

let checkResult;
try { checkResult = JSON.parse(checkRes.body); } catch (e) {
  return { json: { ...j, _execute_outcome: 'checksum_unreadable', _execute_detail: `PA /check-rowcount returned non-JSON (HTTP ${checkRes.status})`, _report: `[db-write-pipeline] proposal ${submissionId} CHECKSUM ERROR` } };
}

if (!checkResult.ok) {
  // Mismatch détecté APRÈS COMMIT — V1.1 trade-off (cf note ci-dessus).
  // Freeze la procédure via apply-graduation et alerte Discord.
  const graduUrl = $env.PA_INTERNAL_BASE_URL + '/api/v1/admin/db-pipeline/apply-graduation';
  const graduBody = JSON.stringify({ procedure, new_trust_level: 'frozen', money_tier: manifest.money_tier || 'non_money' });
  await new Promise((resolve) => {
    const u = new URL(graduUrl);
    const lib = u.protocol === 'https:' ? https : http;
    const req = lib.request({
      method: 'POST', hostname: u.hostname, port: u.port || (u.protocol === 'https:' ? 443 : 80),
      path: u.pathname, headers: { 'Content-Type': 'application/json', 'X-Internal-API-Key': internalKey, 'Content-Length': Buffer.byteLength(graduBody) },
    }, (res) => { res.on('data', () => {}); res.on('end', resolve); });
    req.on('error', () => resolve()); req.write(graduBody); req.end();
  });
  return { json: { ...j, _execute_outcome: 'checksum_mismatch_frozen', _execute_detail: checkResult.mismatches.join(' ; '), _observed: checkResult.observed, _expected: checkResult.expected, _report: `🔥 [db-write-pipeline] proposal ${submissionId} CHECKSUM MISMATCH — procédure ${procedure} FROZEN. observed=${JSON.stringify(checkResult.observed)} expected=${JSON.stringify(checkResult.expected)}` } };
}

return { json: { ...j, _execute_outcome: 'committed', _observed: checkResult.observed, _report: `[db-write-pipeline] proposal ${submissionId} EXECUTED (checksum OK). observed=${JSON.stringify(checkResult.observed)}` } };

// Builds the two Anthropic Messages API request bodies for the LLM review.
// One pass = one focused question. The reviewer is a FRESH context: prompts
// are built here from the proposal + dry-run results only — no link to the
// agent that authored the proposal.
const j = $('Dry-run + invariants').first().json;
const args = JSON.stringify(j.args || {});
const checks = JSON.stringify(j._check_results || []);
const sqlText = j.mode === "new" ? j.new_procedure_sql : "(existing catalogued procedure)";
const SYSTEM = "You are an independent reviewer of a proposed database write for the Ratis backend. You did NOT write this proposal; your value is a fresh, skeptical look. Reply with ONLY a JSON object: {"verdict": "ok" | "not_ok", "reason": "<one or two sentences>"}. No text outside the JSON.";
const pass1 = "Review pass: INTENT. Question: does the procedure actually do what the proposal claims?

Stated rationale: " + j.rationale + "
Procedure: " + j.procedure + "
Arguments: " + args + "
Procedure SQL: " + sqlText + "
Dry-run check results: " + checks + "

Return verdict not_ok if the procedure's real effect diverges from the stated rationale.";
const pass2 = "Review pass: MAGIC CASE. Question: is the dry-run result correct only by coincidence of this specific test case?

Example failure: a WHERE user_id=X modifies exactly 1 row only because that user happens to have a single balance row; another user would have N. A rowcount=1 invariant would then be a coincidence, not a guarantee.

Stated rationale: " + j.rationale + "
Procedure: " + j.procedure + "
Arguments: " + args + "
Procedure SQL: " + sqlText + "
Dry-run check results: " + checks + "

Return verdict not_ok if the invariants hold for this test case but would not generalise.";
function bodyFor(userPrompt) {
  return { model: "claude-sonnet-4-6", max_tokens: 1024, system: SYSTEM, messages: [{ role: "user", content: userPrompt }] };
}
return { json: { ...j, _llm_pass1_body: bodyFor(pass1), _llm_pass2_body: bodyFor(pass2) } };

// Aggregates the 2 LLM passes into one verdict.
// not_ok if any pass is not_ok ; unavailable if any pass could not be
// evaluated (API down / malformed JSON) — never silently 'ok'.
// The LLM review is a SECONDARY filter: invariants + human are the real gates.
function parsePass(name, item) {
  try {
    const text = (((item || {}).content || [])[0] || {}).text;
    if (!text) return { pass: name, verdict: "unavailable", reason: "no LLM response" };
    const parsed = JSON.parse(text.trim());
    const raw = String(parsed.verdict || "").toLowerCase();
    const v = (raw === "ok" || raw === "not_ok") ? raw : "unavailable";
    return { pass: name, verdict: v, reason: parsed.reason || "" };
  } catch (e) {
    return { pass: name, verdict: "unavailable", reason: "unparseable LLM response" };
  }
}
const p = $('Dry-run + invariants').first().json;
const r1 = parsePass("intent", $('LLM pass 1 (intent)').first().json);
const r2 = parsePass("magic_case", $('LLM pass 2 (magic case)').first().json);
const feedback = [r1, r2];
let verdict = "ok";
if (r1.verdict === "not_ok" || r2.verdict === "not_ok") verdict = "not_ok";
else if (r1.verdict === "unavailable" || r2.verdict === "unavailable") verdict = "unavailable";
const out = { ...p, _llm_verdict: verdict, _llm_feedback: feedback, _llm_unavailable: verdict === "unavailable" };
if (verdict === "not_ok") {
  out._response_status = "rejected";
  out._response_stage = "llm_review";
  out._response_feedback = feedback;
  out._report = "[db-write-pipeline] proposal " + p.submission_id + " REJECTED at llm_review. " + JSON.stringify(feedback);
} else {
  out._response_status = "pending_human_approval";
  out._report = "[db-write-pipeline] proposal " + p.submission_id + " passed machine gates — pending human approval." + (verdict === "unavailable" ? " LLM review unavailable — reinforced human review required." : "");
}
return { json: out };

// The invariants gate failed in the sandbox dry-run — build the rejection
// response for the agent (stage = invariants).
const j = $input.first().json;
return { json: { ...j,
  _response_status: "rejected",
  _response_stage: "invariants",
  _response_feedback: j._check_results || [],
  _report: "[db-write-pipeline] proposal " + j.submission_id + " REJECTED at invariants. " + JSON.stringify(j._check_results || [])
} };

// SP6 — scan tables-argent. Inspecte le SQL de la procedure pour les
// tables sensibles ; pose _touches_money_tables. Tourne AVANT Sandbox
// Down (sandbox encore up pour le SELECT prosrc).
// HSP4 M4 : mode=new supprimé — toutes les procédures sont catalog-only.
const { execSync } = require("child_process");
const j = $input.first().json;
const p = $('IF HMAC OK').first().json;
const SENSITIVE = [
  /cashback_[a-z_]+/i,
  /\\buser_cab_balance\\b/i,
  /\\buser_cashback_balance\\b/i,
  /\\bsubscriptions\\b/i,
  /\\bcashback_withdrawals\\b/i,
  /\\bcashback_transactions\\b/i,
];
let sqlToScan = "";
// Mode existing — recupere la source cataloguee depuis la sandbox.
try {
  const up = $('Sandbox Up').first().json;
  const upOut = JSON.parse((up.stdout || "{}").trim().split("\n").pop());
  const container = upOut.container;
  // M7 — defense in depth : same shape check as Dry-run. If invalid we DO NOT
  // exec docker — return early flagged as money-table (fail-safe : badge ON).
  if (!/^ratis-sandbox-[0-9]+-[0-9]+$/.test(String(container || ""))) {
    return { json: { ...j, _touches_money_tables: true, _money_scan_error: "invalid sandbox container shape" } };
  }
  const q = "SELECT prosrc FROM pg_proc WHERE proname = '" + p.procedure.replace(/'/g, "''") + "'";
  const cmd = `ssh mac-mini-host \"docker exec -i ${container} psql -tA -U ratis -d ratis_prod -c \\\"${q}\\\"\"`;
  sqlToScan = execSync(cmd, { encoding: "utf8", timeout: 15000 });
} catch (e) {
  // Source inaccessible — prudence : on force le badge tables-argent.
  return { json: { ...j, _touches_money_tables: true, _money_scan_error: String(e) } };
}
const touches = SENSITIVE.some((re) => re.test(sqlToScan));
return { json: { ...j, _touches_money_tables: touches } };

// HSP3 M2 — verifie le MAC calcule par PA avec N8N_RESUME_SECRET
// et confirme submission_id avant de construire l'outcome.
const crypto = require('crypto');
const proposal = $('IF HMAC OK').first().json;
const resume = $input.first().json;
const body   = resume.body || resume;
const decision = body.decision;
const presentedMac = body.mac || '';
const submissionIdFromBody = body.submission_id || '';

const sid = $('Register approval').first().json.submission_id;
if (submissionIdFromBody !== sid) {
  return { json: { ...proposal, _outcome: 'rejected_mac', _report: '[db-write-pipeline] proposal ' + sid + ' resume MAC verification \u2014 submission_id mismatch.' } };
}

const resumeSecret = $env.N8N_RESUME_SECRET;
if (!resumeSecret) throw new Error('N8N_RESUME_SECRET env not set in n8n');

const expected = crypto.createHmac('sha256', resumeSecret).update(sid + decision).digest('hex');
const a = Buffer.from(presentedMac, 'hex');
const b = Buffer.from(expected, 'hex');
if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) {
  return { json: { ...proposal, _outcome: 'rejected_mac', _report: '[db-write-pipeline] proposal ' + sid + ' resume MAC verification FAILED \u2014 agent forgery suspected.' } };
}

// L3 fix — ne pas swallow l'erreur silencieusement. Si LLM synthesis n'a pas
// tourné (branche break-glass) c'est attendu → llmUnavailable=false sans warn.
// Si le node existe mais .first() raise (race), on flag _llm_unavailable=true
// (fail-safe : examen humain renforcé) au lieu de tomber sur false.
let llmUnavailable = false;
const llmNode = $('LLM synthesis');
if (llmNode) {
  try {
    llmUnavailable = llmNode.first().json._llm_unavailable || false;
  } catch (e) {
    // Le node existe dans le workflow mais .first() a échoué — fail-safe : on
    // marque unavailable pour que l'examen humain reste renforcé en cas de
    // doute. L'erreur est tracée via _llm_read_error.
    llmUnavailable = true;
    proposal._llm_read_error = String(e).slice(0, 200);
  }
}
const base = { ...proposal, _llm_unavailable: llmUnavailable };

if (decision === 'approve') {
  return { json: { ...base, _outcome: 'approve', _operator: body.operator || '?',
    _report: '[db-write-pipeline] proposition ' + sid + ' APPROUVEE par ' + (body.operator || '?') + '.' } };
}
if (decision === 'reject') {
  return { json: { ...base, _outcome: 'reject', _operator: body.operator || '?', _reason: body.reason || '',
    _report: '[db-write-pipeline] proposition ' + sid + ' REJETEE par ' + (body.operator || '?') + ' \u2014 motif : ' + (body.reason || '') } };
}
return { json: { ...base, _outcome: 'expired',
  _report: '[db-write-pipeline] proposition ' + sid + ' EXPIREE \u2014 aucune decision sous 24 h.' } };

// HSP3.1 — trust_level effectif = override BDD (app_settings.db_pipeline_trust_levels)
// sinon manifest.trust_level_initial. n8n consulte l'endpoint PA get-trust-level ;
// fail-safe : si PA injoignable/erreur, fallback sur le manifest seul (comportement
// HSP3 V1 préservé — ne casse pas le pipeline si PA indispo).
const https = require('https');
const http = require('http');
const j = $input.first().json;
const manifest = j._manifest_snapshot || {};
const initialLevel = manifest.trust_level_initial || 'manual';

let effective = initialLevel;
try {
  const paUrl = $env.PA_ADMIN_BASE_URL + '/api/v1/admin/db-pipeline/get-trust-level';
  const internalKey = $env.INTERNAL_API_KEY;
  const body = JSON.stringify({ procedure: j.procedure, manifest_trust_level_initial: initialLevel });
  const result = await new Promise((resolve, reject) => {
    const u = new URL(paUrl);
    const lib = u.protocol === 'https:' ? https : http;
    const req = lib.request({
      method: 'POST', hostname: u.hostname, port: u.port || (u.protocol === 'https:' ? 443 : 80),
      path: u.pathname,
      headers: { 'Content-Type': 'application/json', 'X-Internal-API-Key': internalKey, 'Content-Length': Buffer.byteLength(body) },
    }, (res) => { let buf = ''; res.on('data', (c) => { buf += c; }); res.on('end', () => resolve({ status: res.statusCode, body: buf })); });
    req.on('error', reject);
    req.write(body); req.end();
  });
  if (result.status === 200) {
    const parsed = JSON.parse(result.body);
    if (parsed.effective_trust_level) effective = parsed.effective_trust_level;
  }
  // status !== 200 → garde le fallback manifest (effective = initialLevel).
} catch (e) {
  // PA injoignable / parse error → fail-safe sur le manifest.
  effective = initialLevel;
}

if (effective === 'frozen') {
  return { json: { ...j, _trust_level: 'frozen', _response_status: 'rejected', _response_stage: 'trust_level_frozen', _report: '[db-write-pipeline] proposal ' + j.submission_id + ' REJECTED \u2014 procedure trust_level=frozen.' } };
}
if (effective === 'caps_only' && (manifest.money_tier === 'cab' || manifest.money_tier === 'non_money')) {
  return { json: { ...j, _trust_level: 'caps_only', _skip_human_gate: true } };
}
return { json: { ...j, _trust_level: 'manual', _skip_human_gate: false } };

// HSP3 M3 — fige summary_fr dans la proposal avant Register approval.
const prev = $('LLM synthesis').first().json;
const resp = $input.first().json || {};
const summary = resp.summary_fr || null;
const summaryError = resp.summary_error || null;
return { json: { ...prev, _summary_fr: summary, _summary_error: summaryError } };

// HSP3 M4 — fige anomaly_flags dans la proposal.
const prev = $('Merge summary into proposal').first().json;
