// HSP4 M2 — re-vérification d'identité après HMAC.
// 3 checks : (1) agent_id matche regex, (2) fenêtre anti-replay 5 min,
// (3) agent_id ∈ manifest.allowed_callers (manifest chargé via PA).
const crypto = require('crypto');
const https = require('https');
const proposal = $input.first().json;

// Check 1 — regex agent_id.
const aid = proposal.agent_id || '';
if (!/^[a-z][a-z0-9_-]{2,31}$/.test(aid)) {
  return { json: { ...proposal, _identity_status: 'invalid_agent_id', _identity_detail: 'agent_id ne respecte pas la regex ^[a-z][a-z0-9_-]{2,31}$' } };
}

// Check 2 — proposed_at dans la fenêtre 5 min.
const proposedAt = Date.parse(proposal.proposed_at || '');
if (Number.isNaN(proposedAt)) {
  return { json: { ...proposal, _identity_status: 'invalid_proposed_at', _identity_detail: 'proposed_at absent ou non-ISO-8601' } };
}
const nowMs = Date.now();
const skewMs = Math.abs(nowMs - proposedAt);
if (skewMs > 5 * 60 * 1000) {
  return { json: { ...proposal, _identity_status: 'stale_proposal', _identity_detail: `proposed_at hors fenêtre 5 min (skew=${Math.round(skewMs/1000)}s)` } };
}

// Check 3 — allowed_callers via fetch manifeste depuis PA.
// On charge le manifeste TOML décodé via un endpoint PA qui le sert en
// JSON (équivalent du dict `body.manifest` côté validate-args). Pour
// V1.1 on lit le fichier directement via fs (les manifestes sont sur
// le même volume Mac mini que n8n).
const fs = require('fs');
const manifestPath = `/Users/guillaume/Cursor/Ratis/db/procedures/${proposal.procedure}.manifest.toml`;
let allowedCallers = [];
try {
  const raw = fs.readFileSync(manifestPath, 'utf-8');
  // Parsing TOML très simple : on cherche la ligne `allowed_callers = [...]`.
  const m = raw.match(/allowed_callers\s*=\s*\[([^\]]*)\]/);
  if (m) {
    allowedCallers = m[1].split(',').map(s => s.trim().replace(/^"|"$/g, '')).filter(Boolean);
  }
} catch (e) {
  return { json: { ...proposal, _identity_status: 'manifest_unreadable', _identity_detail: `manifest ${proposal.procedure}.manifest.toml inaccessible : ${e.message}` } };
}
if (!allowedCallers.includes(aid)) {
  return { json: { ...proposal, _identity_status: 'caller_not_allowed', _identity_detail: `agent_id ${aid} absent de allowed_callers (${allowedCallers.join(', ')})` } };
}

return { json: { ...proposal, _identity_status: 'ok' } };

// HSP4 M3 — délègue la validation des args à l'endpoint PA validate-args.
// Single source de vérité (Python validate_args) — pas de drift JS/Python.
const https = require('https');
const http = require('http');
const fs = require('fs');
const proposal = $input.first().json;

// Charge le manifeste TOML brut depuis le filesystem (même approche que
// Validate identity — V1.1 mono-host).
const manifestPath = `/Users/guillaume/Cursor/Ratis/db/procedures/${proposal.procedure}.manifest.toml`;
let manifestText;
try {
  manifestText = fs.readFileSync(manifestPath, 'utf-8');
} catch (e) {
  return { json: { ...proposal, _args_status: 'manifest_unreadable', _args_detail: e.message } };
}

// Très simple toml→json : on parse les sections [[args]] et les scalaires top-level
// dont on a besoin (name, purpose, facing, direction, money_tier, trust_level_initial,
// allowed_callers). Suffisant pour faire le body POST — PA re-valide le manifeste.
// (Implémentation explicite plutôt que require d'une lib toml absente du runtime n8n.)
function parseScalar(line) {
  const m = line.match(/^([a-z_]+)\s*=\s*(.+)$/);
  if (!m) return null;
  let v = m[2].trim();
  if (v.startsWith('"') && v.endsWith('"')) v = v.slice(1, -1);
  else if (/^(true|false)$/.test(v)) v = v === 'true';
  else if (/^[0-9]+$/.test(v)) v = Number(v);
  else if (v.startsWith('[')) v = v.slice(1, -1).split(',').map(s => s.trim().replace(/^"|"$/g, '')).filter(Boolean);
  return [m[1], v];
}
const manifest = { args: [], affects: [] };
let current = null;
for (const line of manifestText.split('\n')) {
  const l = line.trim();
  if (l === '' || l.startsWith('#')) continue;
  if (l === '[[args]]') { current = {}; manifest.args.push(current); continue; }
  if (l === '[[affects]]') { current = {}; manifest.affects.push(current); continue; }
  const kv = parseScalar(l);
  if (!kv) continue;
  if (current === null) { manifest[kv[0]] = kv[1]; } else { current[kv[0]] = kv[1]; }
}

// Appel PA validate-args.
const paUrl = $env.PA_INTERNAL_BASE_URL + '/api/v1/admin/db-pipeline/validate-args';
const internalKey = $env.INTERNAL_API_KEY;
const body = JSON.stringify({ manifest, args: proposal.args });
const result = await new Promise((resolve, reject) => {
  const u = new URL(paUrl);
  const lib = u.protocol === 'https:' ? https : http;
  const req = lib.request({
    method: 'POST',
    hostname: u.hostname,
    port: u.port || (u.protocol === 'https:' ? 443 : 80),
    path: u.pathname,
    headers: { 'Content-Type': 'application/json', 'X-Internal-API-Key': internalKey, 'Content-Length': Buffer.byteLength(body) },
  }, (res) => {
    let buf = '';
    res.on('data', (c) => { buf += c; });
    res.on('end', () => resolve({ status: res.statusCode, body: buf }));
  });
  req.on('error', reject);
  req.write(body);
  req.end();
});
if (result.status !== 200) {
  return { json: { ...proposal, _args_status: 'pa_unreachable', _args_detail: `HTTP ${result.status} from PA validate-args` } };
}
const parsed = JSON.parse(result.body);
if (!parsed.ok) {
  return { json: { ...proposal, _args_status: 'invalid_args', _args_detail: parsed.detail, _manifest_snapshot: manifest } };
}
return { json: { ...proposal, _args_status: 'ok', _manifest_snapshot: manifest } };
